#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);  // 高速入出力
    cin.tie(nullptr);

    int H, W;
    cin >> H >> W;

    vector<vector<int>> A(H, vector<int>(W));
    for (int i = 0; i < H; i++)
        for (int j = 0; j < W; j++)
            cin >> A[i][j];

    // 行の合計を計算
    vector<long long> row(H, 0);
    for (int i = 0; i < H; i++)
        for (int j = 0; j < W; j++)
            row[i] += A[i][j];

    // 列の合計を計算
    vector<long long> col(W, 0);
    for (int i = 0; i < H; i++)
        for (int j = 0; j < W; j++)
            col[j] += A[i][j];

    // 各マスの答えを出力
    for (int i = 0; i < H; i++) {
        for (int j = 0; j < W; j++) {
            if (j > 0) cout << ' ';
            cout << row[i] + col[j] - A[i][j];
        }
        cout << '\n';
    }
}

