use strict;
use warnings;

my ($H, $W) = split ' ', <STDIN>;
my @A;
for (0..$H-1) {
    push @A, [split ' ', <STDIN>];
}

my @row = map { my $r = $_; my $s = 0; $s += $_ for @$r; $s } @A;
my @col = (0) x $W;
for my $i (0..$H-1) {
    for my $j (0..$W-1) {
        $col[$j] += $A[$i][$j];
    }
}

for my $i (0..$H-1) {
    print join(' ', map { $row[$i] + $col[$_] - $A[$i][$_] } 0..$W-1) . "\n";
}

